mapper.select:
SELECT id,memory_type, summary, memory, memory_hash, parent_id, session_id, create_time, update_time, user_id
FROM long_term_memory
WHERE user_id = #{userId}

    AND session_id = #{sessionId}


    AND memory_type = #{memoryType}


    AND (update_time > #{beginDateTime} OR memory_type!='taskRecords')

ORDER BY update_time desc

SELECT id, memory_type, summary, memory, memory_hash, parent_id, session_id, create_time, update_time, user_id
FROM long_term_memory
WHERE user_id = #{userId}

    AND session_id = #{sessionId}


    AND memory_type = #{memoryType}


    AND update_time < #{endDateTime}

ORDER BY update_time desc

SELECT id, memory_type, summary, memory, memory_hash, parent_id, session_id, create_time, update_time, user_id
FROM long_term_memory
WHERE user_id = #{userId} AND memory_type = #{memoryType}

SELECT id,memory_type, summary, memory, memory_hash, parent_id, session_id, create_time, update_time, user_id, embedding_id
FROM long_term_memory
WHERE id = #{id}

